CREATE INDEX IF NOT EXISTS "action_logs_status_idx" ON "action_logs" USING btree ("status");

CREATE INDEX IF NOT EXISTS "approvals_run_history_id_idx" ON "approvals" USING btree ("run_history_id");
CREATE INDEX IF NOT EXISTS "approvals_action_log_id_idx" ON "approvals" USING btree ("action_log_id");
CREATE INDEX IF NOT EXISTS "approvals_status_idx" ON "approvals" USING btree ("status");
CREATE INDEX IF NOT EXISTS "approvals_requested_at_idx" ON "approvals" USING btree ("requested_at");

