CREATE INDEX IF NOT EXISTS "trigger_metadata_agent_definition_id_idx" ON "trigger_metadata" USING btree ("agent_definition_id");
CREATE INDEX IF NOT EXISTS "trigger_metadata_trigger_key_idx" ON "trigger_metadata" USING btree ("trigger_key");
